import{_ as e,o as s,c as l,ag as a}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Type System Comparison","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/archive/Comparison/03_Type_System.md","filePath":"archive/extra/archive/Comparison/03_Type_System.md"}'),n={name:"archive/extra/archive/Comparison/03_Type_System.md"};function d(o,t,i,c,r,y){return s(),l("div",null,[...t[0]||(t[0]=[a(`<h1 id="type-system-comparison" tabindex="-1">Type System Comparison <a class="header-anchor" href="#type-system-comparison" aria-label="Permalink to &quot;Type System Comparison&quot;">​</a></h1><p>This document compares Vex&#39;s type system with Go, Rust, C, and C++.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">Vex</th><th style="text-align:left;">Go</th><th style="text-align:left;">Rust</th><th style="text-align:left;">C</th><th style="text-align:left;">C++</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Strong Typing</strong></td><td style="text-align:left;">Yes</td><td style="text-align:left;">Yes</td><td style="text-align:left;">Yes</td><td style="text-align:left;">Weak</td><td style="text-align:left;">Moderate</td></tr><tr><td style="text-align:left;"><strong>Type Inference</strong></td><td style="text-align:left;">Function body local</td><td style="text-align:left;">Function body local</td><td style="text-align:left;">Function body local</td><td style="text-align:left;"><code>auto</code> (C23)</td><td style="text-align:left;"><code>auto</code></td></tr><tr><td style="text-align:left;"><strong>Structs</strong></td><td style="text-align:left;"><code>struct</code></td><td style="text-align:left;"><code>struct</code></td><td style="text-align:left;"><code>struct</code></td><td style="text-align:left;"><code>struct</code></td><td style="text-align:left;"><code>class</code> / <code>struct</code></td></tr><tr><td style="text-align:left;"><strong>Methods</strong></td><td style="text-align:left;">External (<code>fn (s: &amp;T)</code>)</td><td style="text-align:left;">External (<code>func (s *T)</code>)</td><td style="text-align:left;">Implement block (<code>impl T</code>)</td><td style="text-align:left;">N/A</td><td style="text-align:left;">Internal (Class body)</td></tr><tr><td style="text-align:left;"><strong>Interfaces</strong></td><td style="text-align:left;"><code>contract</code></td><td style="text-align:left;"><code>interface</code></td><td style="text-align:left;"><code>trait</code></td><td style="text-align:left;">N/A</td><td style="text-align:left;">Abstract Class</td></tr><tr><td style="text-align:left;"><strong>Generics</strong></td><td style="text-align:left;">Yes (<code>&lt;T&gt;</code>)</td><td style="text-align:left;">Yes (<code>[T]</code>)</td><td style="text-align:left;">Yes (<code>&lt;T&gt;</code>)</td><td style="text-align:left;">No (<code>void*</code>)</td><td style="text-align:left;">Templates (<code>&lt;T&gt;</code>)</td></tr><tr><td style="text-align:left;"><strong>Enums</strong></td><td style="text-align:left;">Sum Types (Data variants)</td><td style="text-align:left;">Integer constants</td><td style="text-align:left;">Sum Types</td><td style="text-align:left;">Integers</td><td style="text-align:left;">Integers / <code>enum class</code></td></tr><tr><td style="text-align:left;"><strong>Union Types</strong></td><td style="text-align:left;"><code>TypeA | TypeB</code></td><td style="text-align:left;">No</td><td style="text-align:left;">No (Use Enums)</td><td style="text-align:left;"><code>union</code> (C-style)</td><td style="text-align:left;"><code>std::variant</code></td></tr><tr><td style="text-align:left;"><strong>Tuple</strong></td><td style="text-align:left;"><code>(A, B)</code></td><td style="text-align:left;">No</td><td style="text-align:left;"><code>(A, B)</code></td><td style="text-align:left;">N/A</td><td style="text-align:left;"><code>std::tuple</code></td></tr><tr><td style="text-align:left;"><strong>Aliasing</strong></td><td style="text-align:left;"><code>type Name = Type</code></td><td style="text-align:left;"><code>type Name Type</code></td><td style="text-align:left;"><code>type Name = Type</code></td><td style="text-align:left;"><code>typedef</code></td><td style="text-align:left;"><code>using</code></td></tr></tbody></table><h2 id="distinctive-features" tabindex="-1">Distinctive Features <a class="header-anchor" href="#distinctive-features" aria-label="Permalink to &quot;Distinctive Features&quot;">​</a></h2><h3 id="contracts-vs-traits-vs-interfaces" tabindex="-1">Contracts vs Traits vs Interfaces <a class="header-anchor" href="#contracts-vs-traits-vs-interfaces" aria-label="Permalink to &quot;Contracts vs Traits vs Interfaces&quot;">​</a></h3><ul><li><strong>Vex Contracts</strong>: Similar to Rust traits but allow for both static dispatch and dynamic usage (future). Uses <code>impl Contract</code> syntax on the struct definition line, unlike Rust&#39;s separate <code>impl Trait for Type</code> block.</li><li><strong>Go Interfaces</strong>: Implicit implementation. If methods match, it implements it.</li><li><strong>Rust Traits</strong>: Explicit implementation block.</li></ul><h3 id="enums" tabindex="-1">Enums <a class="header-anchor" href="#enums" aria-label="Permalink to &quot;Enums&quot;">​</a></h3><p>Vex Enums are true sum types, capable of holding data (like Rust).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum Message {</span></span>
<span class="line"><span>    Quit,</span></span>
<span class="line"><span>    Move { x: i32, y: i32 },</span></span>
<span class="line"><span>    Write(string),</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="method-syntax" tabindex="-1">Method Syntax <a class="header-anchor" href="#method-syntax" aria-label="Permalink to &quot;Method Syntax&quot;">​</a></h3><p>Vex adopts a hybrid &quot;Go-style&quot; definition for methods to keep structs simple data containers, but uses <code>let!</code> for mutability.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn (p: &amp;Point) distance() {}</span></span>
<span class="line"><span>fn (p: &amp;Point!) move(x: i32, y: i32) {}</span></span></code></pre></div>`,12)])])}const f=e(n,[["render",d]]);export{g as __pageData,f as default};
